actions.script:
String q = (query ?: "").toLowerCase().trim()
int max = (maxResults ?: 25) as int
for (def t in toolList) {
    if (q) {
        String hay = "${t.toolName ?: ''} ${t.verb ?: ''} ${t.noun ?: ''} ${t.description ?: ''}".toLowerCase()
        if (!hay.contains(q)) continue
    }
    def m = t.getMap()
    m.effect = m.effectEnumId   // ergonomic alias the LLM/screen reads
    capabilityList.add(m)
    if (capabilityList.size() >= max) break
}

String q = (query ?: "").toLowerCase().trim()
List catalogNouns = toolList.collect { it.noun }.findAll { it && (!q || (it as String).toLowerCase().contains(q)) }.unique()

// Builder Knowledgebase: real grounded terms. With a query, snap via lexical find; without
// one, return all APPROVED glossary terms (the full grounding slice).
List<String> kbTerms = []
if (q) {
    def found = ec.service.sync().name("ai.GlossaryServices.find#DomainTerm")
        .parameters([text: query]).call()
    kbTerms = (found.terms ?: []).collect { (it.term as String) }
} else {
    kbTerms = ec.entity.find("moqui.ai.AiDomainTerm").condition("statusId", "AI_TERM_APPROVED")
        .orderBy("term").list().collect { (it.term as String) }
}

// glossary is primary; catalog nouns merged as a floor. source reflects whether the KB spoke.
source = kbTerms ? "knowledgebase" : "catalog"
termList = (kbTerms + catalogNouns).findAll { it }.unique()

// heuristic floor: derive a slug from the intent + KB-grounded nouns. list#DomainTerm with
// no query returns the full grounding slice (APPROVED glossary terms + catalog nouns);
// pick the term that appears in the intent.
def terms = ec.service.sync().name("ai.ComposerServices.list#DomainTerm").parameters([:]).call().termList ?: []
String noun = terms.find { (intent as String).toLowerCase().contains((it as String).toLowerCase()) } ?: "assistant"
// snap the chosen noun to its canonical glossary term (dialect -> canonical), if the KB knows it
if (noun != "assistant") {
    try {
        def snap = ec.service.sync().name("ai.GlossaryServices.propose#Naming")
            .parameters([proposedNoun: noun, intentText: intent]).call()
        if (snap?.noun) noun = snap.noun
    } catch (Throwable t) { ec.logger.warn("propose#Naming glossary snap skipped: ${t.message}") }
}
String slug = (noun == "assistant" ? "assistant" : "${noun}-assistant")
agentNameSuggestion = slug.toLowerCase().replaceAll(/[^a-z0-9-]+/, "-").replaceAll(/-+/, "-")
descriptionSuggestion = "Assistant for: ${intent}"
// optional LLM refinement (best-guess): only if a provider is configured. Guarded — never aborts.
try {
    def ai = ec.factory.getTool("AI", org.moqui.ai.AiToolFactory.class)
    String providerName = System.getProperty("ai_openai_key") ? "openai" :
        (System.getProperty("ai_anthropic_key") ? "anthropic" : null)
    if (providerName) {
        def provider = ai.getProvider(providerName)
        def resp = provider.chat([model: providerName == "openai" ? "gpt-4o-mini" : "claude-3-5-haiku-latest",
            systemContext: "Suggest a short, lowercase, hyphenated agent name (<=4 words) and a one-line description. " +
                "Ground the name in these business terms when relevant: ${terms.join(', ')}. " +
                "Reply as JSON {\"name\":\"...\",\"description\":\"...\"}.",
            messages: [[role: "user", content: intent as String]]])
        if (resp?.assistantText) {
            def j = new groovy.json.JsonSlurper().parseText(resp.assistantText as String)
            if (j.name) agentNameSuggestion = (j.name as String).toLowerCase().replaceAll(/[^a-z0-9-]+/, "-").replaceAll(/-+/, "-")
            if (j.description) descriptionSuggestion = j.description
        }
    }
} catch (Throwable t) { ec.logger.warn("propose#Naming LLM refine skipped: ${t.message}") }

def ai = ec.factory.getTool("AI", org.moqui.ai.AiToolFactory.class)
def r = new org.moqui.ai.AgentRunner(ec, ai).runPreview(agentId as String, testMessage as String)
agentRunId = r.agentRunId; statusId = r.statusId; assistantMessage = r.assistantMessage
heldCalls = []
for (def a in ec.entity.find("moqui.ai.AiToolApproval").condition("agentRunId", agentRunId)
        .condition("statusId", "AI_APPR_PENDING").orderBy("requestedDate").list())
    heldCalls.add([toolName: a.toolName, serviceName: a.serviceName, arguments: a.arguments])
